import os

# Load funding data
funding_path = var_functions.query_db_8
if isinstance(funding_path, str):
    with open(funding_path, 'r') as f:
        funding_data = json.load(f)
else:
    funding_data = funding_path

# Load civic documents  
civic_path = var_functions.query_db_10
if isinstance(civic_path, str):
    with open(civic_path, 'r') as f:
        civic_docs = json.load(f)
else:
    civic_docs = civic_path

# Find park projects completed in 2022
park_projects_completed_2022 = []

# Projects mentioned as completed in 2022 in the documents:
completed_projects_2022 = [
    'Bluffs Park Shade Structure',  # completed November 2022
    'Broad Beach Road Water Quality Repair',  # completed November 2022  
    'Point Dume Walkway Repairs'  # completed November 2022
]

# Check which of these are park-related and have funding
for project_name in completed_projects_2022:
    if 'park' in project_name.lower():
        for funding_item in funding_data:
            if funding_item['Project_Name'] == project_name:
                park_projects_completed_2022.append({
                    'name': project_name,
                    'amount': int(funding_item['Amount'])
                })

# Also search for other park projects mentioned as completed in 2022
for doc in civic_docs:
    text = doc['text'].lower()
    if 'park' in text and 'completed' in text and '2022' in text:
        # Look for project names that contain 'park'
        for funding_item in funding_data:
            proj_name_lower = funding_item['Project_Name'].lower()
            if 'park' in proj_name_lower:
                # Check if this project is mentioned in the document
                if funding_item['Project_Name'].lower() in text:
                    # Check if it's marked as completed in 2022
                    lines = doc['text'].split('\n')
                    for line in lines:
                        line_lower = line.lower()
                        if funding_item['Project_Name'].lower() in line_lower and 'completed' in line_lower and '2022' in line_lower:
                            amount = int(funding_item['Amount'])
                            # Add if not already in list
                            if not any(p['name'] == funding_item['Project_Name'] for p in park_projects_completed_2022):
                                park_projects_completed_2022.append({
                                    'name': funding_item['Project_Name'],
                                    'amount': amount
                                })

# Calculate total funding
total_funding = sum(p['amount'] for p in park_projects_completed_2022)

print('__RESULT__:')
print(json.dumps({
    'project_count': len(park_projects_completed_2022),
    'total_funding': total_funding,
    'projects': park_projects_completed_2022
}))"}

